  description: "Delivers institutional insights through CRM Analytics dashboards covering recruitment yield, enrollment trends, retention rates, student success metrics, and financial health. Education Analytics provides pre-built dashboard templates for directors, recruiters, admissions officers, and advisors, each tailored to their decision-making needs. Custom report building enables institutions to create ad-hoc analyses specific to their reporting requirements.",
  components: [
    {id:"director-insights",name:"Director Insights",icon:"\u{1F3E2}",desc:"A multi-page dashboard providing institutional leadership with a comprehensive view of key performance indicators across recruitment, enrollment, retention, and graduation outcomes. The overview page surfaces year-over-year trends and highlights metrics that deviate significantly from targets. Drill-down pages let directors explore specific areas in detail.",tags:[],connections:[]},
    {id:"recruitment-analytics",name:"Recruitment Analytics",icon:"\u{1F4C8}",desc:"Tracks recruitment funnel metrics including inquiry volume, event attendance, application submission rates, and yield percentages by channel, territory, and counselor. Conversion rate analysis identifies which recruitment activities produce the highest-quality applicants. Trend comparisons across recruitment cycles reveal shifts in prospect behavior and channel effectiveness.",tags:[],connections:[{planet:"recruitment",desc:"Recruitment funnel data feeds analytics"}]},
    {id:"student-success-metrics",name:"Student Success Metrics",icon:"\u{1F3C6}",desc:"Monitors retention, persistence, GPA distribution, credit accumulation, and graduation rates across student populations. Cohort analysis compares outcomes for different student groups, revealing disparities that inform equity-focused interventions. At-risk indicators aggregate multiple signals into early warning visualizations.",tags:[],connections:[{planet:"success",desc:"Success tracking data powers analytics"}]},
    {id:"financial-analytics",name:"Financial Analytics",icon:"\u{1F4B0}",desc:"Provides visibility into tuition revenue, financial aid distribution, receivables aging, and payment plan utilization. Revenue forecasting models project future enrollment-driven revenue based on admissions pipeline data. Aid effectiveness analysis shows how different aid packaging strategies affect enrollment yield and net tuition revenue.",tags:[],connections:[{planet:"financials",desc:"Financial data feeds revenue dashboards"}]}
  ],
