  name: "Agentforce",
  icon: "\u{1F916}",
  color: "#a855f7",
  description: "Deploys AI-powered agents across the student lifecycle to automate communication, answer questions, and surface actionable insights. Agentforce for Education Cloud includes specialized agents for recruitment outreach, admissions Q&A, academic advising, financial aid guidance, and alumni engagement. Each agent is configured with education-specific topics, guardrails, and institutional knowledge.",
  components: [
    {id:"recruitment-agent",name:"Recruitment Agent",icon:"\u{1F4E3}",desc:"Automates personalized outreach to prospective students through email, SMS, and chat channels. The recruitment agent answers questions about programs, campus life, and application requirements using institutional knowledge bases. It identifies high-intent prospects based on interaction patterns and escalates them to human counselors for personal follow-up.",tags:[],connections:[{planet:"recruitment",desc:"Automates recruitment outreach sequences"}]},
    {id:"admissions-agent",name:"Admissions Agent",icon:"\u{1F4CB}",desc:"Provides real-time application status updates and answers common admissions questions through conversational AI. The agent handles inquiries about document requirements, decision timelines, and next steps after admission. It integrates with the application data model to provide personalized, context-aware responses.",tags:[],connections:[{planet:"admissions",desc:"Answers applicant questions about their application"}]},
    {id:"success-agent",name:"Student Success Agent",icon:"\u{1F31F}",desc:"Assists students with academic planning, course selection, and career exploration through personalized conversations. The success agent can access a student's enrollment history, degree requirements, and competency records to provide context-aware guidance. It recommends courses based on remaining requirements and warns about prerequisite gaps.",tags:[],connections:[{planet:"success",desc:"AI advising surfaces at-risk students"}]},
    {id:"financials-agent",name:"Student Financials Agent",icon:"\u{1F4B0}",desc:"Answers questions about account balances, fee breakdowns, payment due dates, and financial aid status. The financials agent provides self-service resolution for common billing inquiries that would otherwise require staff assistance. It can explain how charges were calculated and direct students to appropriate resources.",tags:[],connections:[{planet:"financials",desc:"Handles billing and aid inquiries"}]},
    {id:"alumni-agent",name:"Alumni Agent",icon:"\u{1F3C5}",desc:"Engages alumni through personalized communication about giving opportunities, events, and volunteer activities. The alumni agent can provide gift history summaries, answer questions about tax receipts, and facilitate event registration. It identifies engagement patterns that suggest readiness for increased giving or volunteer involvement.",tags:[],connections:[{planet:"alumni",desc:"Manages alumni outreach and engagement"}]}
  ],
  dataFlow:["Agent is configured with education-specific topics and guardrails","Student or prospect initiates conversation through portal or messaging","Agent accesses relevant records to provide personalized responses","Complex inquiries are escalated to human staff with full context","Agent performance metrics feed into analytics dashboards"],
